theme_scss:
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700;800&display=swap");
// backward compatibility. deprecated in v15
$font-family-sans-serif: "Poppins", "InterVariable", "Inter", -apple-system, BlinkMacSystemFont,
	"Segoe UI", "Roboto", "Oxygen", "Ubuntu", "Cantarell", "Fira Sans",
	"Droid Sans", "Helvetica Neue", sans-serif;

// override font stack if custom font is set in website theme
:root {
	--font-stack: "Poppins", "InterVariable", "Inter", -apple-system, BlinkMacSystemFont,
	"Segoe UI", "Roboto", "Oxygen", "Ubuntu", "Cantarell", "Fira Sans",
	"Droid Sans", "Helvetica Neue", sans-serif !important;
}
$primary: #6D28D9;$dark: #2E1065;$body-text-color: #1E1B2E;$body-bg: #F8F7FF;$enable-shadows: false;
$enable-gradients: true;
$enable-rounded: true;

// Bootstrap Variable Overrides


// Import themes from installed apps
@import "frappe/public/scss/website.bundle";
@import "erpnext/public/scss/website";



// Custom Theme


:root {

	--primary: #{$primary};
	--primary-color: #{$primary};

	--bg-color: #{$body-bg};

	--text-color: #{$body-text-color};
	--text-light: #{$body-text-color};
	}
